using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record TicketRequest(string Subject, string Description, int Priority);

public record PredictionResponse(
    string PredictedCategory,
    Dictionary<string, float> Probabilities);

public record EvaluationResponse(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    IReadOnlyList<CategoryMetric> PerCategoryMetrics);

public record CategoryMetric(string Category, double Precision, double Recall, double F1Score);

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly IDataView _trainingData;
    private readonly string[] _categoryNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _trainingData = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainModel();
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered category names from the label key so scores map correctly.
        var labelColumn = _trainingData.Schema["Category"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(_trainingData.Schema)["Score"]
            .GetSlotNames(ref slotNames);
        _categoryNames = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();
    }

    private ITransformer TrainModel()
    {
        // Combine Subject + Description into a single text field, featurize it,
        // then concatenate with the numeric Priority feature.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        return pipeline.Fit(_trainingData);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < _categoryNames.Length; i++)
        {
            probabilities[_categoryNames[i]] = prediction.Score[i];
        }

        return new PredictionResponse(prediction.Category, probabilities);
    }

    public EvaluationResponse Evaluate()
    {
        // Use cross-validation to get meaningful metrics from the small dataset.
        var labelPipeline = _mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category));

        var featurePipeline = labelPipeline
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(_trainingData, featurePipeline, numberOfFolds: 3, labelColumnName: "Label");

        var avgMacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);
        var avgLogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction);

        // Per-category metrics from full training data evaluation.
        var predictions = _model.Transform(_trainingData);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var perCategory = metrics.PerClassLogLoss
            .Select((logLoss, i) =>
            {
                var confusionMatrix = metrics.ConfusionMatrix;
                var precision = confusionMatrix.PerClassPrecision[i];
                var recall = confusionMatrix.PerClassRecall[i];
                var f1 = precision + recall > 0
                    ? 2 * precision * recall / (precision + recall)
                    : 0;
                var name = i < _categoryNames.Length ? _categoryNames[i] : $"Class{i}";
                return new CategoryMetric(name, precision, recall, f1);
            }).ToList();

        return new EvaluationResponse(
            avgMacroAccuracy, avgMicroAccuracy, avgLogLoss, avgLogLossReduction, perCategory);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var prediction = _classifier.Predict(request);
        return Ok(prediction);
    }

    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        var evaluation = _classifier.Evaluate();
        return Ok(evaluation);
    }
}

